var e=[{id:`L2_1`,type:`dialog`,speaker:`SERGEANT_GRONIA_PAJAMAS_NULL`,text:{KOREA:`후으으… 이게 뭐라고 가슴이 다 두근거리네.`,JPN:`ふうう……変にドキドキしちゃうな。`,ENG:`Hngh... Why's my heart pounding...?`,TWN:`欸…這是怎樣？我的心跳得好快。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SERGEANT_GRONIA_PAJAMAS_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SERGEANT_GRONIA_PAJAMAS_NULL`,text:{KOREA:`…아, 아프냐고요? 아니, 그게…`,JPN:` ……ぐ、具合が悪そう？　あ、いや……`,ENG:` A-am I feeling ill? No, but...`,TWN:`我…我是不是哪裡不舒服嗎？沒有，那個…`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SERGEANT_GRONIA_PAJAMAS_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SERGEANT_GRONIA_PAJAMAS_NULL`,text:{KOREA:`크흠. 저희 일단 오늘은 서로 안전 거리를 좀 유지하죠.`,JPN:` ゴホン。とりあえず今日はお互い距離を保ちましょう。`,ENG:` Ahem! I believe we should keep our distance for the time being.`,TWN:`咳，我們今天還是先保持安全距離吧，`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SERGEANT_GRONIA_PAJAMAS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SERGEANT_GRONIA_PAJAMAS_NULL`,text:{KOREA:`간격을 좁힐 시간이야, 앞으로도 넉넉할 테고요.`,JPN:` これからいくらでも距離を縮める時間はあるでしょうし。`,ENG:` We'll have enough time later to get close.`,TWN:`以後有的是時間可以縮短距離。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SERGEANT_GRONIA_PAJAMAS_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};